content:
{
  "sentences": [
    {
      "text": "請你說慢一點，我聽不懂你的意思。",
      "pinyin": "Qǐng nǐ shuō màn yīdiǎn, wǒ tīng bù dǒng nǐ de yìsi.",
      "pinyin_numeric": "qing3 ni3 shuo1 man4 yi1dian3, wo3 ting1 bu4 dong3 ni3 de yi4si.",
      "translation_en": "Please speak more slowly; I don't understand what you mean.",
      "translation_ko": "천천히 말씀해 주세요. 당신의 뜻을 이해하지 못하겠어요."
    },
    {
      "text": "對不起，我說錯了，請你再說一次。",
      "pinyin": "Duìbuqǐ, wǒ shuō cuò le, qǐng nǐ zài shuō yī cì.",
      "pinyin_numeric": "dui4buqi3, wo3 shuo1 cuo4 le, qing3 ni3 zai4 shuo1 yi1 ci4.",
      "translation_en": "Sorry, I said it wrong. Please say it again.",
      "translation_ko": "죄송합니다. 제가 잘못 말했어요. 다시 한 번 말씀해 주세요."
    },
    {
      "text": "原來是這樣，我以為你說錯了，其實沒有。",
      "pinyin": "Yuánlái shì zhèyàng, wǒ yǐwéi nǐ shuō cuò le, qíshí méiyǒu.",
      "pinyin_numeric": "yuan2lai2 shi4 zhe4yang4, wo3 yi3wei2 ni3 shuo1 cuo4 le, qi2shi2 mei2you3.",
      "translation_en": "So that's how it is. I thought you made a mistake, but actually you didn't.",
      "translation_ko": "그랬군요. 당신이 잘못 말한 줄 알았는데, 사실은 아니었네요."
    },
    {
      "text": "你的意思到底是什麼？請你解釋清楚。",
      "pinyin": "Nǐ de yìsi dàodǐ shì shénme? Qǐng nǐ jiěshì qīngchu.",
      "pinyin_numeric": "ni3 de yi4si dao4di3 shi4 shen2me? qing3 ni3 jie3shi4 qing1chu.",
      "translation_en": "What exactly do you mean? Please explain clearly.",
      "translation_ko": "당신의 뜻이 도대체 무엇인가요? 분명히 설명해 주세요."
    },
    {
      "text": "我以為你誤會了，其實我想說的是別的意思。",
      "pinyin": "Wǒ yǐwéi nǐ wùhuì le, qíshí wǒ xiǎng shuō de shì bié de yìsi.",
      "pinyin_numeric": "wo3 yi3wei2 ni3 wu4hui4 le, qi2shi2 wo3 xiang3 shuo1 de shi4 bie2 de yi4si.",
      "translation_en": "I thought you misunderstood. Actually, I meant something else.",
      "translation_ko": "당신이 오해한 줄 알았어요. 사실 제가 말하려던 것은 다른 뜻이었어요."
    },
    {
      "text": "請你慢一點說，這樣我才能聽懂。",
      "pinyin": "Qǐng nǐ màn yīdiǎn shuō, zhèyàng wǒ cái néng tīng dǒng.",
      "pinyin_numeric": "qing3 ni3 man4 yi1dian3 shuo1, zhe4yang4 wo3 cai2 neng2 ting1 dong3.",
      "translation_en": "Please speak more slowly so that I can understand.",
      "translation_ko": "천천히 말씀해 주세요. 그래야 제가 알아들을 수 있어요."
    },
    {
      "text": "對不起，我剛才說錯了，請你改一下。",
      "pinyin": "Duìbuqǐ, wǒ gāngcái shuō cuò le, qǐng nǐ gǎi yīxià.",
      "pinyin_numeric": "dui4buqi3, wo3 gang1cai2 shuo1 cuo4 le, qing3 ni3 gai3 yi1xia4.",
      "translation_en": "Sorry, I just said it wrong. Please correct it.",
      "translation_ko": "죄송합니다. 방금 제가 잘못 말했어요. 고쳐 주세요."
    },
    {
      "text": "你的句子有錯誤，請你確認一下答案。",
      "pinyin": "Nǐ de jùzi yǒu cuòwù, qǐng nǐ quèrèn yīxià dá'àn.",
      "pinyin_numeric": "ni3 de ju4zi you3 cuo4wu4, qing3 ni3 que4ren4 yi1xia4 da2'an4.",
      "translation_en": "There's an error in your sentence. Please confirm the answer.",
      "translation_ko": "당신의 문장에 오류가 있어요. 답을 확인해 주세요."
    },
    {
      "text": "我以為你問的是那個問題，其實不是。",
      "pinyin": "Wǒ yǐwéi nǐ wèn de shì nàge wèntí, qíshí bùshì.",
      "pinyin_numeric": "wo3 yi3wei2 ni3 wen4 de shi4 na4ge wen4ti2, qi2shi2 bu4shi4.",
      "translation_en": "I thought you were asking about that question, but actually you weren't.",
      "translation_ko": "당신이 그 문제를 물어본 줄 알았는데, 사실은 아니었어요."
    },
    {
      "text": "換句話說，你的意思是我們要改時間嗎？",
      "pinyin": "Huàn jùhuà shuō, nǐ de yìsi shì wǒmen yào gǎi shíjiān ma?",
      "pinyin_numeric": "huan4 ju4hua4 shuo1, ni3 de yi4si shi4 wo3men yao4 gai3 shi2jian1 ma?",
      "translation_en": "In other words, do you mean we need to change the time?",
      "translation_ko": "다시 말해, 당신의 뜻은 우리가 시간을 변경해야 한다는 건가요?"
    }
  ]
}
